import './Slide.scss';

import { Button } from ':components/Button';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React from 'react';

import type { SlideProps } from './Slide.types';

export const Slide: FC<SlideProps> = ({ title, body, actions }) => (
	<div className="dsb_slide" data-testid="Slide">
		<div className="dsb_slide-title">
			<Typography className="dsb_slide-title-text" variant="h5">
				{title}
			</Typography>
		</div>
		<Typography className="dsb_slide-body" variant="body3">
			{body}
		</Typography>
		{actions && (
			<div className="dsb_slide-footer">
				<div className="dsb_slide-footer-actions">
					{actions.map((action, index) => {
						const handleClick = (): void => {
							action.onClick?.();
						};
						return (
							<Button
								key={index}
								variant="plain"
								onClick={handleClick}
								className={classNames(
									'dsb_slide-footer-actions-action',
									index > 0 && 'dsb_slide-footer-actions-action__chained',
								)}
							>
								{action.label}
							</Button>
						);
					})}
				</div>
			</div>
		)}
	</div>
);
